import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { BookOpenIcon, GraduationCapIcon, UsersIcon, ShieldAlertIcon } from 'lucide-react';
import { CourseDiscovery } from './pages/CourseDiscovery';
import { StudentDashboard } from './pages/StudentDashboard';
import { VolunteerDashboard } from './pages/VolunteerDashboard';
import { AdminDashboard } from './pages/AdminDashboard';

const TABS = [
  { id: 'discovery', label: 'Course Discovery', icon: BookOpenIcon },
  { id: 'student', label: 'Student Dashboard', icon: GraduationCapIcon },
  { id: 'volunteer', label: 'Volunteer Dashboard', icon: UsersIcon },
  { id: 'admin', label: 'Admin Panel', icon: ShieldAlertIcon }
];

function App() {
  const [activeTab, setActiveTab] = useState('discovery');

  const renderContent = () => {
    switch (activeTab) {
      case 'discovery':
        return <CourseDiscovery />;
      case 'student':
        return <StudentDashboard />;
      case 'volunteer':
        return <VolunteerDashboard />;
      case 'admin':
        return <AdminDashboard />;
      default:
        return <CourseDiscovery />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 font-sans text-gray-900 flex flex-col">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-40 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row md:items-center justify-between py-4 gap-4">
            <div className="flex items-center space-x-2 flex-shrink-0">
              <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center shadow-sm">
                <GraduationCapIcon className="w-5 h-5 text-white" />
              </div>
              <span className="text-xl font-bold text-gray-900 tracking-tight">TutorConnect</span>
            </div>

            <nav className="flex overflow-x-auto hide-scrollbar pb-1 md:pb-0 -mx-4 px-4 md:mx-0 md:px-0">
              <div className="flex space-x-1 bg-gray-100/80 p-1 rounded-xl">
                {TABS.map((tab) => {
                  const isActive = activeTab === tab.id;
                  const Icon = tab.icon;

                  return (
                    <button
                      key={tab.id}
                      onClick={() => setActiveTab(tab.id)}
                      className={`relative flex items-center space-x-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors whitespace-nowrap outline-none ${
                        isActive ? 'text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-200/50'
                      }`}
                    >
                      {isActive && (
                        <motion.div
                          layoutId="activeTabIndicator"
                          className="absolute inset-0 bg-white rounded-lg shadow-sm border border-gray-200/50"
                          initial={false}
                          transition={{ type: 'spring', stiffness: 500, damping: 30 }}
                        />
                      )}
                      <span className="relative z-10 flex items-center">
                        <Icon className={`w-4 h-4 mr-2 ${isActive ? 'text-indigo-600' : 'text-gray-400'}`} />
                        {tab.label}
                      </span>
                    </button>
                  );
                })}
              </div>
            </nav>
          </div>
        </div>
      </header>

      <main className="flex-1 w-full">
        <motion.div key={activeTab} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.3 }} className="h-full">
          {renderContent()}
        </motion.div>
      </main>
    </div>
  );
}

export default App;
